pub fn zmemcpy(dst: &mut [u8], src: &[u8], n: usize) {
    let len = n.min(dst.len()).min(src.len());
    dst[..len].copy_from_slice(&src[..len]);
}

pub fn zmemcmp(s1: &[u8], s2: &[u8], n: usize) -> i32 {
    let len = n.min(s1.len()).min(s2.len());
    for i in 0..len {
        if s1[i] != s2[i] {
            return (s1[i] as i32) - (s2[i] as i32);
        }
    }
    0
}

pub fn zmemzero(buffer: &mut [u8], len: usize) {
    let n = len.min(buffer.len());
    for b in &mut buffer[..n] { *b = 0; }
}

pub fn byte_swap(word: u64) -> u64 {
    word.swap_bytes()
}

pub fn bi_reverse(mut code: u32, len: u8) -> u32 {
    let mut res: u32 = 0;
    for _ in 0..len {
        res = (res << 1) | (code & 1);
        code >>= 1;
    }
    res
}
